import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from './AuthContext';
const Login = () => {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const navigate = useNavigate();
    const [loading, setLoading] = useState(false);
    const { login } = useAuth();

      async function handleLogin() {
    if (loading) return;
    setLoading(true);

    try {
        const res = await axios.post('/api/user/login', { email, password }, { withCredentials: true });
        await login();
        navigate('/home');
    } catch (error) {
        if (error.response) {
            const status = error.response.status;
            const message = error.response.data?.message || 'Login failed.';

            if (status === 401) {
                alert('Incorrect password.');
            } else if (status === 404) {
                alert('User does not exist.');
            } else {
                alert(message);
            }
        } else {
            alert('Something went wrong. Please try again.');
        }
    } finally {
        setLoading(false);
    }
}

    return (
        <>
            <div className="login-container">
                <div className="login">
                    <div className="sub-heading-login">
                        <p>Please enter your details</p>
                    </div>
                    <div className="heading-login">Welcome back</div>
                    <div className="email-input">
                        <input
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            type="email"
                            placeholder="Email address"
                            className="input-box"
                        />
                    </div>
                    <div className="password-input">
                        <input
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            type="password"
                            placeholder="Password"
                            className="input-box"
                        />
                    </div>
                    <div>
                        <button className="login-button" onClick={handleLogin} disabled={loading}>
                           {loading ? 'Logging in...' : 'Login'}
                        </button>
                    </div>
                    <div>
                        <p className="have-account">
                            Don't have an account? <Link to="/signin">Sign Up</Link>
                        </p>
                    </div>
                </div>
            </div>
            <Stylesheet />
        </>
    );
};

const Stylesheet = () => {
    return <style>{`
                p{
                   color:var(--font-text);
                }
                input{
                    background-color:var(--secondary-color);
                    color:var(--font-text);
                    border:none;
                    font-weight:bold;
                }
               .login{
                   color:var(--font-text);
                   border:2px solid var(--font-text);
                   width:400px;
                   border-radius:10px;
                   display:flex;
                   flex-direction:column;
               }
                .sub-heading-login{
                   color:grey;
                   font-size:15px;
                   display:flex;
                   justify-content:left;
                   padding-left:50px;
                }
                .heading-login{
                   font-weight:bold;
                   font-size:28px;
                   display:flex;
                   justify-content:left;
                   padding-left:50px;
                   margin-bottom:12px;
                }
                .login-container{  
                   height:100vh;             
                   display:flex;
                   align-items:center;
                   justify-content:center;
               }
               .input-box{
                    padding:10px;
                    border-radius:5px;
                    width:70%;
                }
                .email-input,.password-input,.name-input{
                   margin-bottom:20px;
                }
                .remember-box{
                    display:flex;
                    flex-direction:row;
                    gap:5%;
                    align-items:center;
                    margin-bottom:15px;
                    justify-content:center;
                    font-size:15px;
                }
                .signup-button,.login-button{
                    background-color:var(--button-color);
                    color:var(--bg-parchment);
                    width:75%;
                    border:none;
                    margin:10px;
                    border-radius:10px;
                    padding:10px;
                    font-size:1.5rem;
                    font-family: 'January', sans-serif;
                }
                .have-account{
                   cursor:pointer;
                }
            `}</style>
}

export default Login;
